import './Tree.scss';

import { classNames } from ':helpers/classnames';
import type { ReactNode } from 'react';
import React from 'react';
import type { TreeProps } from './Tree.types';
import { TreeProvider } from './TreeContext';
import { TreeNode } from './TreeNode';
import { TreeNodesWrapper } from './TreeNodesWrapper';

export const Tree: React.FC<TreeProps> = ({
	title,
	size = 'small',
	children,
	amount = false,
	multiselect = false,
	onChange = (): void => null,
	onExpand,
	style,
	expandOnArrow = true,
	data,
}) => {
	const renderFromObject = (data): ReactNode =>
		// рекурсивно обходим дерево и строим из него дерево
		data.map(node => {
			const { children, ...treeProps } = node;
			return (
				// проверяем наличие дочерних компонентов в дереве и при их наличии продолжаем рекурсию
				<TreeNode {...treeProps}>{children?.length ? renderFromObject(children) : null}</TreeNode>
			);
		});

	return (
		<TreeProvider callback={onChange}>
			<ul data-testid="Tree" className={classNames(`tree-${size}`, 'dsb_tree')} style={style} role="tree">
				{title && <TreeNode className="tree_title" id="title" title={title}></TreeNode>}
				<TreeNodesWrapper
					size={size}
					amount={amount}
					multiselect={multiselect}
					expandOnArrow={expandOnArrow}
					onExpandCallback={onExpand}
				>
					{data ? renderFromObject(data) : children}
				</TreeNodesWrapper>
			</ul>
		</TreeProvider>
	);
};
